@app.get("/reset-mfa/confirm")
def confirm_reset_mfa():
    token = request.args.get("token", "")
    if not token:
        return jsonify({"error": "missing token"}), 400

    try:
        data = verify_reset_token(token, app.config["RESET_TOKEN_MAX_AGE_SECONDS"])
        email = (data.get("email") or "").strip().lower()
    except SignatureExpired:
        return jsonify({"error": "reset link expired"}), 400
    except BadSignature:
        return jsonify({"error": "invalid reset link"}), 400

    user = users.get(email)
    if not user:
        return jsonify({"error": "invalid reset link"}), 400

    user["mfa_enabled"] = False
    user["mfa_secret"] = None
    user["mfa_reset_requested_at"] = None

    return jsonify({
        "message": "MFA has been reset. You can now log in using only your password."
    }), 200

